// 1. Create domain ops: src/widgets/operations.tsp
import "@typespec/http";
using TypeSpec.Http;

interface WidgetOperations {
  @get
  @doc("List widgets.")
  @operationId("listWidgets")
  list(@query namespace: string): Widget[] | OpenMeterError;
}

// 2. Create barrel: src/widgets/index.tsp
import "./operations.tsp";

// 3. In src/openmeter.tsp — import barrel, bind route+tag, add @tagMetadata:
import "./widgets/index.tsp";
@tagMetadata("Widgets", { description: "Manage widgets." })
namespace OpenMeter {
  @route("/api/v1/widgets")
  @tag("Widgets")
  interface WidgetRoutes extends WidgetOperations {}
}

// src/widgets/main.tsp
import "@typespec/http";
import "@typespec/rest";
using TypeSpec.Http;
using TypeSpec.Rest;
using TypeSpec.Rest.Resource;

@friendlyName("Widget")
model Widget {
  @visibility(Lifecycle.Read)
  id: OpenMeter.ULID;

  @visibility(Lifecycle.Read, Lifecycle.Create, Lifecycle.Update)
  name: string;
}

@friendlyName("WidgetCreate")
model WidgetCreate is ResourceCreateModel<Widget>;

interface WidgetOperations {
  @operationId("listWidgets")
  @get list(): Widget[] | OpenMeterError;

  @operationId("createWidget")
  @post create(@body body: WidgetCreate): Widget | OpenMeterError;
}

// Register in src/cloud/main.tsp AND src/main.tsp:
import "./widgets/main.tsp";
